mapper.select:
SELECT DATE_FORMAT(create_time, '%Y-%m') AS name, COUNT(*) AS value FROM sys_log WHERE DATE_FORMAT(create_time, '%Y-%m' ) IN
#{month}
GROUP BY name ORDER BY name

SELECT TO_CHAR(create_time, 'YYYY-MM') AS name, COUNT(*) AS value FROM sys_log WHERE TO_CHAR(create_time, 'YYYY-MM') IN
#{month}
GROUP BY name ORDER BY name

SELECT DATE_FORMAT(create_time, '%Y-%m') AS name, COUNT(DISTINCT ip) AS value FROM sys_log WHERE DATE_FORMAT(create_time, '%Y-%m' ) IN
#{month}
GROUP BY name ORDER BY name

SELECT TO_CHAR(create_time, 'YYYY-MM') AS name, COUNT(DISTINCT ip) AS value FROM sys_log WHERE TO_CHAR(create_time, 'YYYY-MM') IN
#{month}
GROUP BY name ORDER BY name
